#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>d(n-1),p(n);for(auto&x:d)scanf("%lld",&x);for(auto&x:p)scanf("%lld",&x);long long cost=0,mn=p[0];for(int i=0;i<n-1;i++){mn=min(mn,p[i]);cost+=mn*d[i];}printf("%lld\n",cost);}
